-- ----------------------------------------------------------------------------
-- vw_workflows: Table: Workflows. The NTWF Workflow class — prov:Plan + schema:CreativeWork. Each workflow has Dublin Core metadata (title, description, identifier, created, modified), a lifecycle status from the SKOS scheme, and a collection of WorkflowSteps (ntwf:hasStep).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_workflows CASCADE;
CREATE VIEW vw_workflows WITH (security_invoker = ON) AS
SELECT
  t.workflow_id,
  calc_workflows_relative_path(t.workflow_id) AS relative_path,                 -- Stable, DAG-derived location for this Workflow row. Root segment 'workflows' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_workflows_iri(t.workflow_id) AS iri,                                     -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  calc_workflows_name(t.workflow_id) AS name,                                   -- Short machine-friendly name for the workflow. Used for programmatic reference and URL slug generation.
  t.display_name,
  t.title,                                                                      -- Human-readable title of the workflow. Maps to dct:title from Dublin Core. Example: 'Production Deployment Workflow'.
  t.description,                                                                -- Detailed description of the workflow's purpose and scope. Maps to dct:description from Dublin Core. Should explain what business goal the workflow achieves.
  t.identifier,                                                                 -- External system identifier for cross-referencing. Maps to dct:identifier from Dublin Core. This is the join key back to document management systems, ticket systems, or other operational systems.
  t.modified,                                                                   -- Last modification timestamp. Maps to dct:modified from Dublin Core. Critical for answering CQ5: 'Which workflows haven't been reviewed or updated in twelve months?'
  t.created,                                                                    -- Creation timestamp. Maps to dct:created from Dublin Core. Records when the workflow was first defined.
  t.staleness_threshold_months,                                                 -- The governance POLICY (in months): the full review cadence after which this workflow's compliance documentation is formally out of date. The docs go stale exactly when this review age is exceeded — IsStale fires the instant MonthsSinceModified passes this policy line, with no deferral. The article hardcodes the CQ5 question at twelve months ('which workflows haven't been reviewed in twelve months'); promoting that threshold to a raw, editable field makes the policy itself a fact in the SSoT rather than a constant buried in the IsStale formula — so an org can set a 6-month or 18-month review cadence and the staleness verdict recomputes. Defaults to 12 to match the article.
  t.workflow_status,                                                            -- FK to WorkflowStatusConcepts. Captures the current lifecycle state of the workflow (draft, active, deprecated, archived). Maps to the SKOS CBox status vocabulary.
  t.workflow_steps,                                                             -- Reference to workflow steps. Represents the ntwf:hasStep relationship linking workflows to their constituent steps.
  calc_workflows_count_of_non_proposed_steps(t.workflow_id) AS count_of_non_proposed_steps,-- Calculated count of workflow steps in this workflow. Useful for workflow complexity analysis and reporting.
  calc_workflows_has_more_than1_step(t.workflow_id) AS has_more_than1_step,
  calc_workflows_count_ai_steps(t.workflow_id) AS count_ai_steps,               -- Number of steps in this workflow executed by an AIAgent (rollup over WorkflowSteps.IsExecutedByAI). This is the 'AI-executed' half of the article's CQ3 ('which steps are executed by AI agents') — counted against AIAgent individuals specifically, not the deterministic AutomatedPipeline, which is a disjoint agent type. Also drives the business-payoff query (a workflow is a compliance risk when an AI agent runs a step). Worked example: 2 (the AI risk-assessment step and the AI post-deployment health report).
  calc_workflows_count_human_steps(t.workflow_id) AS count_human_steps,         -- Number of steps executed by a HumanAgent (rollup over WorkflowSteps.IsExecutedByHuman). The 'who actually runs this step' count — distinct from CountHumanRequiredSteps, which counts steps that demand a human decision (requiresHumanApproval). Worked example: 2 (the legal-review step and the release approval gate).
  calc_workflows_count_human_required_steps(t.workflow_id) AS count_human_required_steps,-- Number of steps that require a human decision (rollup over WorkflowSteps.RequiresHumanApproval). This is the 'human-required' half of the article's CQ3 ('which require a human decision'), answered — as the article notes — by a single FILTER on requiresHumanApproval. Worked example: 2 (the legal-review step and the release approval gate).
  calc_workflows_count_approval_consistency_violations(t.workflow_id) AS count_approval_consistency_violations,-- Number of steps that require human approval but are not human-filled (rollup over WorkflowSteps.ApprovalConsistencyViolation). The clean ABox witness: this is 0 for the Production Deployment workflow. A non-zero value is the relational signal of a Suite-4 consistency violation.
  calc_workflows_has_consistency_violation(t.workflow_id) AS has_consistency_violation,-- TRUE iff at least one step breaks the human-approval consistency rule (CountApprovalConsistencyViolations > 0). The boolean witness of model integrity: a clean ABox holds it FALSE. This is what makes a broken rule a first-class input to the compliance verdict — a workflow with any consistency violation cannot be COMPLIANT.
  calc_workflows_has_ai_agent_step(t.workflow_id) AS has_ai_agent_step,         -- TRUE iff at least one step in this workflow is executed by an AIAgent. The structural half of the article's business payoff query.
  calc_workflows_months_since_modified(t.workflow_id) AS months_since_modified, -- Whole months since this workflow was last modified (dct:modified), measured live against NOW(). Drives CQ5 staleness. NOW() is seeded deterministically during conformance so test answers stay stable.
  calc_workflows_is_stale(t.workflow_id) AS is_stale,                           -- TRUE iff the workflow's compliance documentation is past its review policy — i.e. the review age in months exceeds the policy line: MonthsSinceModified > StalenessThresholdMonths. With the default the docs go stale at 12 months. Staleness fires the instant the review comes due — there is no renewal window or deferral. This is the article's CQ5 condition ('which workflows haven't been reviewed in twelve months') stated directly against the editable policy field.
  calc_workflows_is_stale_and_has_ai_agent(t.workflow_id) AS is_stale_and_has_ai_agent,-- The article's headline business question, as one boolean: a workflow that is BOTH stale (not reviewed in 12 months) AND has an AI-executed step — the highest compliance risk. Joins the metadata layer (dct:modified) with the accountability layer (filledBy → AIAgent) the way the closing SPARQL demo does, but as a single derived column.
  calc_workflows_count_derivation_links(t.workflow_id) AS count_derivation_links,-- Number of prov:wasDerivedFrom links among this workflow's artifacts (rollup over WorkflowArtifacts.HasDerivationParent). Answers the lineage half of CQ4: 5 artifacts form a chain with 4 derivation links.
  calc_workflows_count_legal_owned_steps(t.workflow_id) AS count_legal_owned_steps,-- Number of steps in this workflow whose owning department is Legal (rollup over WorkflowSteps.IsLegalOwned). CQ7: exactly one Legal-owned step in the Production Deployment workflow.
  calc_workflows_count_engineering_owned_steps(t.workflow_id) AS count_engineering_owned_steps,-- Number of steps whose owning department is Engineering (rollup over WorkflowSteps.IsEngineeringOwned). Feeds CQ7's Engineering-involvement check.
  calc_workflows_involves_engineering_and_legal(t.workflow_id) AS involves_engineering_and_legal,-- TRUE iff this workflow has at least one Engineering-owned step AND at least one Legal-owned step. Answers CQ7 ('which workflows involve both engineering and legal') as a single boolean — the Production Deployment workflow qualifies (4 Engineering steps + 1 Legal step).
  calc_workflows_count_inferred_precedence_pairs(t.workflow_id) AS count_inferred_precedence_pairs,-- Number of step-ordering pairs that the transitive closure of ntwf:precedesStep INFERRED (rollup over the closure view vw_step_precedence_closure where is_inferred = TRUE). The article's signature count: 6 of the 10 closure pairs were never asserted — including step-1 -> step-5. NOTE: this single-workflow model has exactly one Workflow, so the global closure view is wholly this workflow's; the COUNTIFS is unfiltered because every precedence edge belongs to the Production Deployment DAG.
  calc_workflows_count_asserted_precedence_pairs(t.workflow_id) AS count_asserted_precedence_pairs,-- Number of step-ordering pairs that were directly ASSERTED as ntwf:precedesStep edges (rollup over vw_step_precedence_closure where is_inferred = FALSE) — the hop-1 rows. The article's 4 asserted edges. Together with CountInferredPrecedencePairs (6) this sums to the 10-pair closure, making CountOfPrecedenceClosurePairs an honest asserted+inferred total rather than an unconditional count. Single-workflow note as on CountInferredPrecedencePairs: the global closure view is this workflow's.
  calc_workflows_count_of_precedence_closure_pairs(t.workflow_id) AS count_of_precedence_closure_pairs,-- Total number of step-ordering pairs in the transitive closure of ntwf:precedesStep = asserted (4) + inferred (6) = 10. The article's headline closure cardinality, witnessing that the 4 asserted edges over a 5-step chain close to all 10 (i<j) pairs. Computed as CountAssertedPrecedencePairs + CountInferredPrecedencePairs so the total is provably the sum of the two halves, not a separate unconditional view count that could silently drift from them.
  calc_workflows_count_roles_with_bad_filler_cardinality(t.workflow_id) AS count_roles_with_bad_filler_cardinality,-- Number of roles that do NOT have exactly one filledBy arm set (rollup over Roles.HasExactlyOneFiller = FALSE). The three agent classes are owl:disjointWith one another and ntwf:filledBy is functional, so a clean ABox has 0 such roles — this is the Suite-1 functional/disjointness witness as a single integer. A non-zero value is the relational signal of the Suite-4 disjointness violation (a role filled by two agent classes, or by none). NOTE: this single-workflow model has exactly one Workflow and every Role participates in it, so the count is over all roles; a multi-workflow model would scope it through a role→workflow path.
  calc_workflows_count_agent_type_changes(t.workflow_id) AS count_agent_type_changes,-- Number of filledBy assignment periods that changed the agent CLASS of a role (rollup over RoleAssignments.IsAgentTypeChange = TRUE). NTWF governance distinguishes a same-class personnel/model swap from an agent-type transition; this counts the latter. NOTE: single-workflow model — every Role participates in the one workflow, so the count is over all assignment history; a multi-workflow model would scope it through a role→workflow path.
  calc_workflows_count_compliance_audit_changes(t.workflow_id) AS count_compliance_audit_changes-- Number of filledBy assignment periods that took a previously AI-executed binding and reassigned it to a human (rollup over RoleAssignments.RequiresComplianceAudit = TRUE). NTWF governance treats this as a data operation with compliance implications: changing the agent type of a step from ntwf:AIAgent to ntwf:HumanAgent. Each such row must carry when (ValidFrom) and why (Reason). NOTE: single-workflow scoping as above.
FROM workflows t;

-- ----------------------------------------------------------------------------
-- vw_workflow_steps: Table: WorkflowSteps. The NTWF WorkflowStep class — prov:Activity. Each step is first-class and individually addressable, belongs to one Workflow (ntwf:isStepOf), and is assigned to exactly one Role (ntwf:assignedRole). Step-to-step ordering is modeled in the StepPrecedence junction; the ApprovalGate subtype specializes a step via a 1:1 FK.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_workflow_steps CASCADE;
CREATE VIEW vw_workflow_steps WITH (security_invoker = ON) AS
SELECT
  t.workflow_step_id,
  calc_workflow_steps_parent_path(t.workflow_step_id) AS parent_path,           -- Helper: the Workflows parent's RelativePath, pulled across the Workflow FK. Exists so RelativePath can concatenate the '/steps/' segment using only local-field '&' concat (the transpiler compiles a lookup as a pure passthrough, not a lookup+concat).
  calc_workflow_steps_relative_path(t.workflow_step_id) AS relative_path,       -- Stable, DAG-derived location: this row nests under its Workflows parent. Concatenates the parent's path (ParentPath) with '/steps/' + this row's primary key. The DAG performs the recursion — one hop per table via ParentPath — so the full ancestry is encoded without a recursive formula. Unique by construction.
  calc_workflow_steps_iri(t.workflow_step_id) AS iri,                           -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  calc_workflow_steps_name(t.workflow_step_id) AS name,
  t.display_name,
  t.workflow,                                                                   -- Foreign key to the parent workflow. Represents the inverse of ntwf:hasStep, enabling navigation from step to its containing workflow (ntwf:isStepOf).
  calc_workflow_steps_preceding_step_count(t.workflow_step_id) AS preceding_step_count,-- Number of steps that TRANSITIVELY precede this step in the ntwf:precedesStep ordering — a rollup over the closure view vw_step_precedence_closure counting rows whose to_id is this step (i.e. this step's ancestors). On the linear Production Deployment chain: 0,1,2,3,4. Derived purely from the asserted StepPrecedence edges via their transitive closure; nothing is hand-entered. SequencePosition is this + 1.
  calc_workflow_steps_inferred_sequence_position(t.workflow_step_id) AS inferred_sequence_position,-- The step's ordinal position INFERRED purely from the StepPrecedence edges: 1 + PrecedingStepCount (one plus the number of steps that transitively precede it in vw_step_precedence_closure). On the linear Production Deployment chain: 1,2,3,4,5 — no integer is typed; it is a projection of the asserted ordering edges. This is the DEFAULT position; SequencePositionOverride can pin a different value where the inference is ambiguous (e.g. a branch produces ties). Maps to ntwf:inferredSequencePosition (an effortless extension of the article's ordering).
  t.sequence_position_override,                                                 -- OPTIONAL hand-asserted ordinal position — the article's pure ntwf:sequencePosition functional datatype property, preserved as an override slot. NULL on the linear Production Deployment chain (the inference is unambiguous, so nothing is pinned). When set, it wins over InferredSequencePosition in the resolved SequencePosition — this is how a modeler recovers the owl:FunctionalProperty 'exactly one distinct position per step' guarantee on a partial order / branch where the inferred rank would tie. Maps to ntwf:sequencePosition (the article's asserted functional property).
  calc_workflow_steps_sequence_position(t.workflow_step_id) AS sequence_position,-- The effective ordinal position used everywhere (views, UI, competency questions): the hand-asserted SequencePositionOverride when present, otherwise the edge-derived InferredSequencePosition. IF(SequencePositionOverride <> "", SequencePositionOverride, InferredSequencePosition). This is the honest resolution of the two ways order can be stated: the inference is the default computed from the SSoT (the StepPrecedence edges), and an explicit override only overrides — never a silent guess. On the Production Deployment chain all overrides are null, so this equals InferredSequencePosition = 1,2,3,4,5. Maps to ntwf:sequencePosition for consumers.
  t.assigned_role,                                                              -- Foreign key to the Role responsible for executing this step. Maps to ntwf:assignedRole (owl:FunctionalProperty — exactly one role per step). Critical for implementing Heuristic 2 (role-agent separation): steps point to roles, not directly to agents.
  t.requires_human_approval,                                                    -- Boolean flag indicating whether a human agent must fill the assigned role. Maps to ntwf:requiresHumanApproval. Enables answering CQ3: 'Which steps require human decisions vs. AI execution?'
  t.step_duration_minutes,                                                      -- Expected duration of this step in minutes. Maps to ntwf:stepDurationMinutes (datatype property, not functional). Enables SLA and throughput analysis.
  t.consumes_dataset,                                                           -- FK to Datasets. Records which DCAT dataset this step consumes as input. Kept separate from artifact consumption to preserve DCAT metadata semantics (consumesDataset vs. requiresArtifact).
  t.produces_artifacts,                                                         -- Back-reference to WorkflowArtifacts produced by this step. Inverse of WorkflowArtifacts.ProducedByStep (ntwf:producesArtifact / prov:wasGeneratedBy).
  t.requires_artifacts,                                                         -- FK to WorkflowArtifact(s) this step CONSUMES as input. Maps to ntwf:requiresArtifact (aligned to prov:used). Kept distinct from producesArtifact (prov:generated) and from consumesDataset (dcat:Dataset) so the input/output and artifact/dataset semantics stay separate. Inverse is WorkflowArtifacts.RequiredBySteps.
  t.approval_gate,                                                              -- Back-reference to the ApprovalGate subtype row that specializes this step, if any. Inverse of ApprovalGates.WorkflowStep. A step has zero or one approval gate; when present, the gate adds escalationThresholdHours and marks the step as a blocking decision checkpoint. This models ntwf:ApprovalGate rdfs:subClassOf WorkflowStep as a shared-key 1:1 specialization rather than collapsing two DAG nodes into one.
  t.precedes,                                                                   -- Back-reference to StepPrecedence edges where this step is the FromStep (the predecessor). Inverse of StepPrecedence.FromStep. Together with PrecededBy, lets you walk the ntwf:precedesStep ordering in both directions.
  t.preceded_by,                                                                -- Back-reference to StepPrecedence edges where this step is the ToStep (the successor). Inverse of StepPrecedence.ToStep. Part of the ntwf:precedesStep transitive ordering relationship.
  calc_workflow_steps_executing_human_agent(t.workflow_step_id) AS executing_human_agent,-- The HumanAgent (if any) that executes this step, resolved through ntwf:assignedRole → ntwf:filledBy (the HumanAgent arm). Load-bearing lookup: it follows the role→agent indirection the article relies on, so a step knows its executing agent without per-step agent bindings.
  calc_workflow_steps_executing_ai_agent(t.workflow_step_id) AS executing_ai_agent,-- The AIAgent (if any) that executes this step, resolved through ntwf:assignedRole → ntwf:filledBy (the AIAgent arm). One of the three polymorphic filledBy arms.
  calc_workflow_steps_executing_automated_pipeline(t.workflow_step_id) AS executing_automated_pipeline,-- The AutomatedPipeline (if any) that executes this step, resolved through ntwf:assignedRole → ntwf:filledBy (the AutomatedPipeline arm).
  calc_workflow_steps_executing_agent_type(t.workflow_step_id) AS executing_agent_type,-- Which of the three disjoint agent classes executes this step (HumanAgent / AIAgent / AutomatedPipeline), derived from whichever filledBy arm the assigned role has set. Answers the typing half of CQ3 ('which steps are executed by AI agents, and which require a human decision').
  calc_workflow_steps_is_executed_by_ai(t.workflow_step_id) AS is_executed_by_ai,-- TRUE when this step's assigned role is filled by an AIAgent. Feeds CQ3 and the business payoff query (stale workflows with AI-executed steps).
  calc_workflow_steps_is_executed_by_human(t.workflow_step_id) AS is_executed_by_human,-- TRUE when this step's assigned role is filled by a HumanAgent. Feeds CQ3's human-vs-AI step split.
  calc_workflow_steps_approval_consistency_violation(t.workflow_step_id) AS approval_consistency_violation,-- Detectable-error witness: TRUE iff this step requires human approval (RequiresHumanApproval) yet its assigned role is NOT filled by a HumanAgent. In the OWL ABox this is the rule that only a HumanAgent may fill a role on a requiresHumanApproval step; a clean ABox yields FALSE for every step. This is the relational equivalent of the Suite-4 disjointness/consistency check.
  calc_workflow_steps_approval_is_human_filled(t.workflow_step_id) AS approval_is_human_filled,-- Positive form of the human-only-gate rule: TRUE iff this step's human-approval obligation is satisfied — either the step does not require human approval (vacuously satisfied), or it does and its assigned role is filled by a HumanAgent. The clean Production Deployment ABox yields TRUE for every step. This is the affirmative complement of ApprovalConsistencyViolation: the two are always opposite when approval is required, and this one is additionally TRUE on steps that need no approval.
  calc_workflow_steps_owning_department(t.workflow_step_id) AS owning_department,-- The department that owns this step's assigned role, resolved through AssignedRole → Roles.OwnedBy. Lets a workflow report which departments its steps touch (CQ7: 'which workflows involve both Engineering and Legal, and at what steps do they intersect').
  calc_workflow_steps_is_legal_owned(t.workflow_step_id) AS is_legal_owned,     -- TRUE iff this step's owning department is Legal. Rolls up to CQ7's count of Legal-owned steps (exactly one in the Production Deployment workflow).
  calc_workflow_steps_is_engineering_owned(t.workflow_step_id) AS is_engineering_owned-- TRUE iff this step's owning department is Engineering. Rolls up to CQ7's Engineering-involvement check.
FROM workflow_steps t;

-- ----------------------------------------------------------------------------
-- vw_approval_gates: Table: ApprovalGates. The NTWF ApprovalGate class — rdfs:subClassOf WorkflowStep. Modeled as a class-table-inheritance subtype: each gate row shares identity with exactly one WorkflowStep (via the WorkflowStep 1:1 FK) and carries only the gate-specific attribute, escalationThresholdHours. The step it specializes keeps the common attributes (requiresHumanApproval, assigned role, etc.). This preserves the article's double-typing — a gate IS a step — without collapsing two DAG nodes into one.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_approval_gates CASCADE;
CREATE VIEW vw_approval_gates WITH (security_invoker = ON) AS
SELECT
  t.approval_gate_id,
  calc_approval_gates_parent_path(t.approval_gate_id) AS parent_path,           -- Helper: the WorkflowSteps parent's RelativePath, pulled across the WorkflowStep FK. Exists so RelativePath can concatenate the '/approval-gates/' segment using only local-field '&' concat (the transpiler compiles a lookup as a pure passthrough, not a lookup+concat).
  calc_approval_gates_relative_path(t.approval_gate_id) AS relative_path,       -- Stable, DAG-derived location: this row nests under its WorkflowSteps parent. Concatenates the parent's path (ParentPath) with '/approval-gates/' + this row's primary key. The DAG performs the recursion — one hop per table via ParentPath — so the full ancestry is encoded without a recursive formula. Unique by construction.
  calc_approval_gates_iri(t.approval_gate_id) AS iri,                           -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  calc_approval_gates_name(t.approval_gate_id) AS name,
  t.display_name,
  t.workflow_step,                                                              -- 1:1 FK to the WorkflowStep this gate specializes (subtype shared key). This is the relational expression of ntwf:ApprovalGate rdfs:subClassOf WorkflowStep: the gate row adds escalationThresholdHours to its step. Inverse is WorkflowSteps.ApprovalGate.
  t.escalation_threshold_hours,                                                 -- Integer number of hours that may elapse on a pending gate before the ntwf:delegatesTo chain activates. Maps to ntwf:escalationThresholdHours. Domain applies only to ApprovalGate individuals — which is exactly why the gate is its own subtype table and this attribute does not live on every WorkflowStep.
  calc_approval_gates_gate_role(t.approval_gate_id) AS gate_role,               -- The role responsible for this gate's underlying step, resolved through WorkflowStep → WorkflowSteps.AssignedRole. First hop of the CQ2 chain (gate → role → approver).
  calc_approval_gates_gate_approver_human(t.approval_gate_id) AS gate_approver_human-- The human agent who approves at this gate, resolved through the two-hop chain gate → GateRole → Roles.FilledByHumanAgent. Answers CQ2 ('who is responsible for approving a production deployment') directly: the release-approval gate resolves to the Release Manager role, filled by Maria Gonzalez.
FROM approval_gates t;

-- ----------------------------------------------------------------------------
-- vw_step_precedence: Table: StepPrecedence. The NTWF ntwf:precedesStep ordering relationship, modeled as a first-class step-to-step junction. Each row is one directed edge: FromStep precedes ToStep. ntwf:precedesStep is an owl:TransitiveProperty — the four asserted edges (1->2, 2->3, 3->4, 4->5) imply the full closure of ten ordering pairs (including 1->5, which is never asserted). Each edge is a first-class node in the DAG, never a 'helper' integer.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_precedence CASCADE;
CREATE VIEW vw_step_precedence WITH (security_invoker = ON) AS
SELECT
  t.step_precedence_id,
  calc_step_precedence_parent_path(t.step_precedence_id) AS parent_path,        -- Helper: the WorkflowSteps parent's RelativePath, pulled across the FromStep FK. Exists so RelativePath can concatenate the '/precedence/' segment using only local-field '&' concat (the transpiler compiles a lookup as a pure passthrough, not a lookup+concat).
  calc_step_precedence_relative_path(t.step_precedence_id) AS relative_path,    -- Stable, DAG-derived location: this row nests under its WorkflowSteps parent. Concatenates the parent's path (ParentPath) with '/precedence/' + this row's primary key. The DAG performs the recursion — one hop per table via ParentPath — so the full ancestry is encoded without a recursive formula. Unique by construction.
  calc_step_precedence_iri(t.step_precedence_id) AS iri,                        -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  calc_step_precedence_name(t.step_precedence_id) AS name,                      -- Human-readable edge label derived from its endpoints. Mirrors the FromStep -> ToStep direction.
  t.from_step,                                                                  -- FK to the predecessor WorkflowStep — the step that comes BEFORE. The source of the ntwf:precedesStep edge. Inverse is WorkflowSteps.Precedes.
  t.to_step                                                                     -- FK to the successor WorkflowStep — the step that comes AFTER. The target of the ntwf:precedesStep edge. Inverse is WorkflowSteps.PrecededBy.
FROM step_precedence t;

-- ----------------------------------------------------------------------------
-- vw_roles: Table: Roles. The NTWF Role class — a custom root with no adequate standard match, declared disjoint with WorkflowStep and WorkflowArtifact. Roles are the heart of Heuristic 2 (role-agent separation): WorkflowSteps point to Roles; Roles point to exactly one agent (human, AI, or pipeline) via the polymorphic filledBy relationship. When personnel or models change, one filledBy triple changes and the workflow structure is untouched.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_roles CASCADE;
CREATE VIEW vw_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,
  calc_roles_relative_path(t.role_id) AS relative_path,                         -- Stable, DAG-derived location for this Role row. Root segment 'roles' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_roles_iri(t.role_id) AS iri,                                             -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  calc_roles_name(t.role_id) AS name,
  t.display_name,
  t.label,                                                                      -- Human-readable display name. Maps to rdfs:label. Per Heuristic 6: if you cannot write a clear label, you do not yet understand the concept well enough to model it.
  t.comment,                                                                    -- Detailed description of the role's responsibilities and scope. Maps to rdfs:comment. Should define what the role covers, what it excludes, and how it differs from adjacent roles.
  t.has_capability,                                                             -- FK to AgentCapabilityConcepts. Declares the capability this role requires of its filler. Maps to ntwf:hasCapability. Enables CQ: 'Which roles require AI-specific capabilities?'
  t.filled_by_human_agent,                                                      -- One arm of the polymorphic ntwf:filledBy relationship: FK to the HumanAgent that fills this role today. Exactly one of FilledByHumanAgent / FilledByAIAgent / FilledByAutomatedPipeline is set per role (filledBy is functional; the three agent types are owl:disjointWith each other). Roles whose capability requires human judgment or legal review must use this arm.
  t.filled_by_ai_agent,                                                         -- One arm of the polymorphic ntwf:filledBy relationship: FK to the AIAgent that fills this role today. Exactly one filledBy arm is set per role. An AIAgent may fill probabilistic-capability roles (e.g. risk analysis) but never a role whose step has requiresHumanApproval.
  t.filled_by_automated_pipeline,                                               -- One arm of the polymorphic ntwf:filledBy relationship: FK to the AutomatedPipeline that fills this role today. Exactly one filledBy arm is set per role. Pipelines fill deterministic execution roles (e.g. CI/CD).
  t.owned_by,                                                                   -- Foreign key to the Department that owns this role. Maps to ntwf:ownedBy (owl:FunctionalProperty). Enables answering CQ7: 'Which workflows involve both Engineering and Legal?'
  t.delegates_to,                                                               -- Foreign key to the next Role in the escalation chain. Maps to ntwf:delegatesTo (traversable via the SPARQL property path delegatesTo+). Enables answering CQ6: 'What happens when the Release Manager / VP of Engineering is unavailable?'
  t.workflow_steps,                                                             -- Back-reference to workflow steps assigned to this role. Inverse of WorkflowSteps.AssignedRole.
  t.from_delegates_to,                                                          -- Back-reference: the Role that delegates TO this role (one step up the escalation chain). Inverse of Roles.DelegatesTo.
  t.role_assignments,                                                           -- Back-reference to the temporal filledBy history for this role (every validity period, current and retained). Inverse of RoleAssignments.Role.
  calc_roles_filled_by_arm_count(t.role_id) AS filled_by_arm_count,             -- Number of polymorphic ntwf:filledBy arms set on this role (of FilledByHumanAgent / FilledByAIAgent / FilledByAutomatedPipeline). Should always be exactly 1 — mirroring filledBy being functional and the three agent types being mutually disjoint.
  calc_roles_has_exactly_one_filler(t.role_id) AS has_exactly_one_filler,       -- Disjointness/functional witness: TRUE iff exactly one filledBy arm is set. The three agent classes are owl:disjointWith one another and ntwf:filledBy is functional, so a clean ABox has this TRUE for every role. Setting two arms (a role filled by both a human and an AI) is the Suite-4 disjointness violation — here it flips this to FALSE.
  calc_roles_filler_type(t.role_id) AS filler_type                              -- Which disjoint agent class fills this role (HumanAgent / AIAgent / AutomatedPipeline), from whichever filledBy arm is set. Lets the delegation-chain query confirm CQ6's 'zero AI agents in the escalation chain'.
FROM roles t;

-- ----------------------------------------------------------------------------
-- vw_role_assignments: Table: RoleAssignments. The temporal history of ntwf:filledBy. NTWF's change-management discipline requires that when a filledBy triple is updated the old triple is NOT deleted — it is timestamped and retained, or replaced with a versioned triple carrying a validity period. Each row is one filledBy binding with a ValidFrom / ValidTo validity period and the reason for the change, so that 'which agent was executing this step on March 1, 2026?' is answerable from the graph. The current binding on Roles.FilledBy* is the row whose ValidTo is blank (IsCurrent = TRUE); closed rows preserve provenance and chain of custody. This is the relational equivalent of the ontology's named-graph / versioned-triple retention practice.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_role_assignments CASCADE;
CREATE VIEW vw_role_assignments WITH (security_invoker = ON) AS
SELECT
  t.role_assignment_id,
  calc_role_assignments_parent_path(t.role_assignment_id) AS parent_path,       -- Helper: the Roles parent's RelativePath, pulled across the Role FK. Exists so RelativePath can concatenate the '/assignments/' segment using only local-field '&' concat.
  calc_role_assignments_relative_path(t.role_assignment_id) AS relative_path,   -- Stable, DAG-derived location: this assignment nests under its Role parent. Concatenates the parent's path (ParentPath) with '/assignments/' + this row's primary key. Unique by construction.
  calc_role_assignments_iri(t.role_assignment_id) AS iri,                       -- Opaque stable identifier (the dash-form of RelativePath). The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique.
  calc_role_assignments_name(t.role_assignment_id) AS name,                     -- Human-readable label for this assignment period: the role and the validity window.
  t.role,                                                                       -- FK to the Role this assignment binds an agent to. The subject of the historical ntwf:filledBy triple.
  t.filled_by_human_agent,                                                      -- One arm of the polymorphic filledBy binding for this assignment period: FK to the HumanAgent who filled the role during this window. Exactly one filler arm is set per assignment.
  t.filled_by_ai_agent,                                                         -- One arm of the polymorphic filledBy binding: FK to the AIAgent who filled the role during this window. Exactly one filler arm is set per assignment.
  t.filled_by_automated_pipeline,                                               -- One arm of the polymorphic filledBy binding: FK to the AutomatedPipeline that filled the role during this window. Exactly one filler arm is set per assignment.
  t.valid_from,                                                                 -- Start of the validity period for this filledBy binding (inclusive). A retained/versioned triple carries the validity period. ISO date.
  t.valid_to,                                                                   -- End of the validity period for this filledBy binding (exclusive). Blank means the binding is still current — this is the live ntwf:filledBy value mirrored on Roles. A non-blank value means the binding was superseded; the row is retained (not deleted) to preserve provenance.
  t.reason,                                                                     -- The WHY of the change: the audit record must reflect when that transition happened and why. e.g. 'initial assignment', 'departure / backfill', 'model upgrade', 'compliance reassignment to human'.
  t.prior_filler_type,                                                          -- The agent class (HumanAgent / AIAgent / AutomatedPipeline) of the binding this assignment SUPERSEDED, or blank for the first assignment of a role. Lets the agent-type-change audit (AIAgent -> HumanAgent) be witnessed without re-deriving from the prior row.
  calc_role_assignments_filler_type(t.role_assignment_id) AS filler_type,       -- Which agent class filled the role during this period, derived from the three filler arms. Mirrors Roles.FillerType but for the historical binding.
  calc_role_assignments_is_current(t.role_assignment_id) AS is_current,         -- TRUE iff this is the live binding (ValidTo is blank). The set of IsCurrent rows reproduces exactly the current Roles.FilledBy* values; the rest are retained history. The old triple is never deleted — closed rows stay, only IsCurrent flips.
  calc_role_assignments_was_active_as_of_audit_date(t.role_assignment_id) AS was_active_as_of_audit_date,-- NTWF's signature temporal query: 'which agent was executing this step on March 1, 2026?'. TRUE iff this binding's validity period contains 2026-03-01 (ValidFrom <= the date AND (ValidTo blank OR ValidTo > the date)). ISO dates compare lexically. The single row that is TRUE for a given role names the agent active on the audit date — answerable only because history is retained.
  calc_role_assignments_is_agent_type_change(t.role_assignment_id) AS is_agent_type_change,-- TRUE iff this assignment changed the agent CLASS of the role (PriorFillerType set and different from FillerType). NTWF distinguishes a plain personnel/model swap (same class) from an agent-type transition, which carries compliance weight.
  calc_role_assignments_requires_compliance_audit(t.role_assignment_id) AS requires_compliance_audit-- Changing the agent type of a step from ntwf:AIAgent to ntwf:HumanAgent is a data operation with compliance implications. TRUE iff this assignment took a previously AI-executed binding and reassigned it to a human — the exact transition NTWF governance says the audit record must capture (when + why).
FROM role_assignments t;

-- ----------------------------------------------------------------------------
-- vw_departments: Table: Departments. The NTWF Department class — schema:Organization. First-class entity that enables cross-department intersection queries (CQ7: which workflows involve both Engineering and Legal?). Roles are ownedBy a department.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_departments CASCADE;
CREATE VIEW vw_departments WITH (security_invoker = ON) AS
SELECT
  t.department_id,
  calc_departments_relative_path(t.department_id) AS relative_path,             -- Stable, DAG-derived location for this Department row. Root segment 'departments' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_departments_iri(t.department_id) AS iri,                                 -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  calc_departments_name(t.department_id) AS name,                               -- Human-readable display name of the department. Should match organizational terminology for stakeholder communication.
  t.title,                                                                      -- Formal organizational title of the department. Maps to schema:name / dct:title.
  t.display_name,                                                               -- Machine-friendly name for programmatic reference.
  t.roles                                                                       -- Back-reference to roles owned by this department. Inverse of Roles.OwnedBy.
FROM departments t;

-- ----------------------------------------------------------------------------
-- vw_human_agents: Table: HumanAgents. The NTWF HumanAgent class — foaf:Person + prov:Agent. The only agent type permitted to fill roles whose step has requiresHumanApproval. Disjoint with AIAgent and AutomatedPipeline.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_human_agents CASCADE;
CREATE VIEW vw_human_agents WITH (security_invoker = ON) AS
SELECT
  t.human_agent_id,
  calc_human_agents_relative_path(t.human_agent_id) AS relative_path,           -- Stable, DAG-derived location for this HumanAgent row. Root segment 'human-agents' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_human_agents_iri(t.human_agent_id) AS iri,                               -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  t.name,                                                                       -- Full name of the person. Maps to foaf:name. Note: FOAF's name property is appropriate for persons, not for software systems (which use schema:name).
  t.display_name,
  t.mbox,                                                                       -- Email address of the person. Maps to foaf:mbox. Used for notifications and organizational directory integration.
  t.roles,                                                                      -- Back-reference to roles currently filled by this agent. Inverse of Roles.FilledByHumanAgent.
  t.role_assignments                                                            -- Back-reference to historical filledBy assignment periods in which this human filled a role. Inverse of RoleAssignments.FilledByHumanAgent.
FROM human_agents t;

-- ----------------------------------------------------------------------------
-- vw_ai_agents: Table: AIAgents. The NTWF AIAgent class — prov:SoftwareAgent + ntwf:modelVersion. Distinguished from AutomatedPipeline by probabilistic (vs. deterministic) output semantics. Disjoint with HumanAgent and AutomatedPipeline. May never fill a role whose step has requiresHumanApproval.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_ai_agents CASCADE;
CREATE VIEW vw_ai_agents WITH (security_invoker = ON) AS
SELECT
  t.ai_agent_id,
  calc_ai_agents_relative_path(t.ai_agent_id) AS relative_path,                 -- Stable, DAG-derived location for this AIAgent row. Root segment 'ai-agents' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_ai_agents_iri(t.ai_agent_id) AS iri,                                     -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  t.name,                                                                       -- Display name of the AI agent. Maps to schema:name (not foaf:name, which is for persons).
  t.title,                                                                      -- Descriptive title of the AI agent's function.
  t.display_name,
  t.model_version,                                                              -- Version string of the AI model. Maps to ntwf:modelVersion. Makes AI-produced artifacts auditable at the version level. The domain declaration means this property applies only to AIAgent individuals.
  t.deployed_on,                                                                -- Deployment date of this AI model version. The NTWF graph doubles as an AI system registry: 'risk-classifier-v2.4.1 was deployed on 2026-01-10'. Sourced from the AI system registry feed via the shared Dublin Core contract (dct:date).
  t.roles,                                                                      -- Back-reference to roles currently filled by this AI agent. Inverse of Roles.FilledByAIAgent.
  t.role_assignments,                                                           -- Back-reference to historical filledBy assignment periods filled by this AI agent. Inverse of RoleAssignments.FilledByAIAgent.
  t.attributed_artifacts,                                                       -- Back-reference to WorkflowArtifacts attributed to this AI agent (prov:wasAttributedTo). Inverse of WorkflowArtifacts.AttributedToAIAgent. First leg of the 'blast radius' traversal.
  calc_ai_agents_count_attributed_artifacts(t.ai_agent_id) AS count_attributed_artifacts,-- 'Blast radius', leg 1: how many artifacts are attributed to this AI agent (prov:wasAttributedTo). Counts WorkflowArtifacts whose AttributedToAIAgent is this agent.
  calc_ai_agents_count_impacted_workflows(t.ai_agent_id) AS count_impacted_workflows-- 'Blast radius', summarized: the number of distinct workflows reachable from this agent's attributed artifacts (each artifact is produced by a step that belongs to a workflow). With one workflow in the worked example, an upgrade to an agent that produced any artifact has a blast radius of 1 workflow. Counts artifacts attributed to this agent that resolve to a workflow.
FROM ai_agents t;

-- ----------------------------------------------------------------------------
-- vw_automated_pipelines: Table: AutomatedPipelines. The NTWF AutomatedPipeline class — prov:SoftwareAgent + schema:SoftwareApplication. Distinguished from AIAgent by deterministic (vs. probabilistic) output semantics. Disjoint with HumanAgent and AIAgent. Carries schema:name, not foaf:name.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_automated_pipelines CASCADE;
CREATE VIEW vw_automated_pipelines WITH (security_invoker = ON) AS
SELECT
  t.automated_pipeline_id,
  calc_automated_pipelines_relative_path(t.automated_pipeline_id) AS relative_path,-- Stable, DAG-derived location for this AutomatedPipeline row. Root segment 'automated-pipelines' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_automated_pipelines_iri(t.automated_pipeline_id) AS iri,                 -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  t.name,                                                                       -- Display name of the pipeline. Maps to schema:name (appropriate for software systems, unlike foaf:name which is for persons).
  t.description,                                                                -- Description of what the pipeline does and its execution semantics (deterministic, no probabilistic output).
  t.display_name,
  t.roles,                                                                      -- Back-reference to roles currently filled by this pipeline. Inverse of Roles.FilledByAutomatedPipeline.
  t.role_assignments                                                            -- Back-reference to historical filledBy assignment periods filled by this pipeline. Inverse of RoleAssignments.FilledByAutomatedPipeline.
FROM automated_pipelines t;

-- ----------------------------------------------------------------------------
-- vw_workflow_status_concepts: SKOS controlled vocabulary for workflow lifecycle states (ntwf:WorkflowStatusScheme). Part of the CBox. Concepts are shared across all workflows.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_workflow_status_concepts CASCADE;
CREATE VIEW vw_workflow_status_concepts WITH (security_invoker = ON) AS
SELECT
  t.concept_id,
  calc_workflow_status_concepts_relative_path(t.concept_id) AS relative_path,   -- Stable, DAG-derived location for this WorkflowStatusConcept row. Root segment 'concepts/workflow-status' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_workflow_status_concepts_iri(t.concept_id) AS iri,                       -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  t.pref_label,                                                                 -- Preferred human-readable label. Maps to skos:prefLabel.
  t.alt_label,                                                                  -- Alternative label or synonym. Maps to skos:altLabel.
  t.definition,                                                                 -- Formal definition of the concept. Maps to skos:definition.
  t.scope_note,                                                                 -- Usage guidance for the concept. Maps to skos:scopeNote.
  t.workflows                                                                   -- Back-reference to workflows currently in this status. Inverse of Workflows.WorkflowStatus.
FROM workflow_status_concepts t;

-- ----------------------------------------------------------------------------
-- vw_agent_capability_concepts: SKOS controlled vocabulary for agent capability types (ntwf:AgentCapabilityScheme). Roles declare which capability their filler must have (ntwf:hasCapability). Part of the CBox.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_agent_capability_concepts CASCADE;
CREATE VIEW vw_agent_capability_concepts WITH (security_invoker = ON) AS
SELECT
  t.concept_id,
  calc_agent_capability_concepts_relative_path(t.concept_id) AS relative_path,  -- Stable, DAG-derived location for this AgentCapabilityConcept row. Root segment 'concepts/agent-capability' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_agent_capability_concepts_iri(t.concept_id) AS iri,                      -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  t.pref_label,                                                                 -- Preferred label. Maps to skos:prefLabel.
  t.alt_label,                                                                  -- Alternative label. Maps to skos:altLabel.
  t.definition,                                                                 -- Formal definition. Maps to skos:definition.
  t.scope_note,                                                                 -- Usage guidance. Maps to skos:scopeNote.
  t.roles                                                                       -- Back-reference to roles requiring this capability. Inverse of Roles.HasCapability.
FROM agent_capability_concepts t;

-- ----------------------------------------------------------------------------
-- vw_artifact_type_concepts: SKOS controlled vocabulary for artifact type (ntwf artifact-type scheme). Part of the CBox; NTWF names a CBox concept scheme for artifact types alongside workflow status and agent capabilities. Each artifact is classified via dct:type into one of these concepts.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_artifact_type_concepts CASCADE;
CREATE VIEW vw_artifact_type_concepts WITH (security_invoker = ON) AS
SELECT
  t.concept_id,
  calc_artifact_type_concepts_relative_path(t.concept_id) AS relative_path,     -- Stable, DAG-derived location for this concept row. Root segment 'concepts/artifact-type' + the row's primary key.
  calc_artifact_type_concepts_iri(t.concept_id) AS iri,                         -- Opaque stable identifier (the dash-form of RelativePath). The OWL transpiler mints each individual's IRI from this value.
  t.pref_label,                                                                 -- Preferred human-readable label. Maps to skos:prefLabel.
  t.alt_label,                                                                  -- Alternative label or synonym. Maps to skos:altLabel.
  t.definition,                                                                 -- Formal definition of the concept. Maps to skos:definition.
  t.scope_note,                                                                 -- Usage note clarifying boundaries. Maps to skos:scopeNote.
  t.workflow_artifacts                                                          -- Back-reference to WorkflowArtifacts classified under this concept. Inverse of WorkflowArtifacts.ArtifactType.
FROM artifact_type_concepts t;

-- ----------------------------------------------------------------------------
-- vw_datasets: DCAT datasets consumed by workflow steps. The NTWF mapping of dcat:Dataset. Kept separate from WorkflowArtifacts to preserve DCAT metadata semantics (dcat:Dataset vs. prov:Entity). Answers CQ8: 'What datasets does the review consume, and which AI processed them?'
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_datasets CASCADE;
CREATE VIEW vw_datasets WITH (security_invoker = ON) AS
SELECT
  t.dataset_id,
  calc_datasets_relative_path(t.dataset_id) AS relative_path,                   -- Stable, DAG-derived location for this Dataset row. Root segment 'datasets' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution. The relational analogue of a REST resource path; unique by construction across the whole model.
  calc_datasets_iri(t.dataset_id) AS iri,                                       -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  t.title,                                                                      -- Human-readable dataset name. Maps to dct:title.
  t.identifier,                                                                 -- External system identifier. Maps to dct:identifier. Used for cross-referencing with data catalogs.
  t.modified,                                                                   -- Last modification timestamp. Maps to dct:modified.
  t.distribution_url,                                                           -- URL of the data distribution. Maps to dcat:Distribution. The access endpoint for the dataset.
  t.consumed_by_steps                                                           -- Back-reference to WorkflowSteps that consume this dataset. Inverse of WorkflowSteps.ConsumesDataset.
FROM datasets t;

-- ----------------------------------------------------------------------------
-- vw_workflow_artifacts: Artifacts produced and consumed by workflow steps. The NTWF WorkflowArtifact class — prov:Entity + schema:CreativeWork. The DerivedFromArtifact self-FK encodes the prov:wasDerivedFrom provenance chain; ProducedByStep maps prov:wasGeneratedBy; the AttributedTo* arms map prov:wasAttributedTo to the responsible agent.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_workflow_artifacts CASCADE;
CREATE VIEW vw_workflow_artifacts WITH (security_invoker = ON) AS
SELECT
  t.artifact_id,
  calc_workflow_artifacts_parent_path(t.artifact_id) AS parent_path,            -- Helper: the WorkflowSteps parent's RelativePath, pulled across the ProducedByStep FK. Exists so RelativePath can concatenate the '/artifacts/' segment using only local-field '&' concat (the transpiler compiles a lookup as a pure passthrough, not a lookup+concat).
  calc_workflow_artifacts_relative_path(t.artifact_id) AS relative_path,        -- Stable, DAG-derived location: this row nests under its WorkflowSteps parent. Concatenates the parent's path (ParentPath) with '/artifacts/' + this row's primary key. The DAG performs the recursion — one hop per table via ParentPath — so the full ancestry is encoded without a recursive formula. Unique by construction.
  calc_workflow_artifacts_iri(t.artifact_id) AS iri,                            -- Opaque stable identifier (the dash-form of RelativePath). Because RelativePath has no leading slash, this is a clean SUBSTITUTE of '/' for '-'. The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique — no cross-table primary-key collisions.
  t.title,                                                                      -- Human-readable artifact name. Maps to dct:title.
  t.identifier,                                                                 -- External system identifier. Maps to dct:identifier.
  t.artifact_type,                                                              -- FK to the ArtifactTypeConcepts SKOS concept classifying this artifact. Maps to dct:type. The CBox defines a concept scheme for artifact types.
  t.created,                                                                    -- Creation timestamp. Maps to dct:created.
  t.produced_by_step,                                                           -- FK to the WorkflowStep that produced this artifact. Maps to prov:wasGeneratedBy. Inverse of WorkflowSteps.ProducesArtifacts.
  t.required_by_steps,                                                          -- Back-reference to the WorkflowStep(s) that consume this artifact as input (ntwf:requiresArtifact / prov:used). Inverse of WorkflowSteps.RequiresArtifacts.
  t.derived_from_artifact,                                                      -- Self-FK to the artifact this one was derived from. Maps to prov:wasDerivedFrom. Enables the full provenance chain query (CQ4).
  t.attributed_to_human_agent,                                                  -- FK to HumanAgent responsible for this artifact. One arm of prov:wasAttributedTo (exactly one AttributedTo arm is set per artifact, mirroring the disjoint agent types).
  t.attributed_to_ai_agent,                                                     -- FK to AIAgent responsible for this artifact. One arm of prov:wasAttributedTo.
  t.attributed_to_automated_pipeline,                                           -- FK to AutomatedPipeline responsible for this artifact. One arm of prov:wasAttributedTo.
  calc_workflow_artifacts_producing_agent_type(t.artifact_id) AS producing_agent_type,-- Which disjoint agent class produced this artifact (HumanAgent / AIAgent / AutomatedPipeline), from whichever prov:wasAttributedTo arm is set. Lets CQ4 report which kind of agent each artifact in the lineage came from.
  calc_workflow_artifacts_has_derivation_parent(t.artifact_id) AS has_derivation_parent,-- TRUE iff this artifact was derived from another (prov:wasDerivedFrom is set). Counting these across the chain gives CQ4's '4 derivation links among 5 artifacts' — every artifact except the first has a parent.
  calc_workflow_artifacts_produced_by_workflow(t.artifact_id) AS produced_by_workflow,-- The workflow this artifact belongs to, resolved through ProducedByStep → WorkflowSteps.Workflow (artifact → producing step → workflow). Lets workflow-level rollups (e.g. CountDerivationLinks) aggregate artifacts without a redundant direct FK.
  calc_workflow_artifacts_has_producing_workflow(t.artifact_id) AS has_producing_workflow-- TRUE iff this artifact resolves to a producing workflow (ProducedByWorkflow is set). Lets the AIAgents blast-radius rollup (CountImpactedWorkflows) count only artifacts that reach a workflow, since COUNTIFS needs a boolean criterion column.
FROM workflow_artifacts t;

-- ----------------------------------------------------------------------------
-- vw_governance_roles: Table: GovernanceRoles. NTWF governance names two distinct ontology-governance roles: a Steward (responsible for the ontology's health — monitors drift, tracks external dependency updates, fields user questions, maintains docs, keeps the validation suite current; identifies that a change is needed but has no approval power) and an Authority (the power to approve changes to the CBox, ABox, and TBox; decides how and where a change is made; sits with the function that owns the domain). 'A steward who can make TBox or ABox changes without authority review is a single point of failure.' For an organization under 500 people a single person may hold both roles. This table models the maintenance discipline itself, as data, so the change log can attribute approvals to a named authority.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_governance_roles CASCADE;
CREATE VIEW vw_governance_roles WITH (security_invoker = ON) AS
SELECT
  t.governance_role_id,
  calc_governance_roles_relative_path(t.governance_role_id) AS relative_path,   -- Stable, DAG-derived location for this GovernanceRole row. Root segment 'governance-roles' + the row's primary key.
  calc_governance_roles_iri(t.governance_role_id) AS iri,                       -- Opaque stable identifier (the dash-form of RelativePath). The OWL transpiler mints each individual's IRI from this value.
  calc_governance_roles_name(t.governance_role_id) AS name,                     -- Slug form of the display name.
  t.display_name,                                                               -- Human-readable name of the governance role (e.g. 'Steward', 'Authority').
  t.kind,                                                                       -- Which of the two NTWF governance kinds this is: 'Steward' or 'Authority'.
  t.responsibilities,                                                           -- What this role is responsible for. Steward: monitor drift, track external dependency updates, field user questions, maintain documentation, keep the validation suite current. Authority: approve changes to CBox/ABox/TBox; decide how and where a change is made.
  t.approval_scope,                                                             -- The boxes this role may approve changes to (CBox/ABox/TBox), or 'none' for a Steward — who can identify that a change is needed but cannot approve it.
  t.held_by,                                                                    -- The person or function holding this role. The steward is naturally whoever owns the engineering knowledge infrastructure; authority sits with the workflow governance function that owns the modeled domain. Under 500 people, one person may hold both.
  calc_governance_roles_can_approve_changes(t.governance_role_id) AS can_approve_changes,-- TRUE iff this governance role carries approval power (Kind = 'Authority'). A Steward returns FALSE — a steward making TBox/ABox changes without authority review is a single point of failure.
  t.approved_changes                                                            -- Back-reference to ChangeLog entries this governance role approved. Inverse of ChangeLog.ApprovedBy.
FROM governance_roles t;

-- ----------------------------------------------------------------------------
-- vw_change_log: Table: ChangeLog. NTWF's minimum governance artifact: 'a change log that records every TBox and ABox modification, with its rationale.' Each entry records the four facts NTWF governance enumerates — the competency question that motivated the change, the terms affected, the version number of the release, and the date — plus the rationale and the Authority who approved it. Semantic-versioning discipline (MAJOR.MINOR.PATCH) is captured per entry via ChangeKind.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_change_log CASCADE;
CREATE VIEW vw_change_log WITH (security_invoker = ON) AS
SELECT
  t.change_log_id,
  calc_change_log_relative_path(t.change_log_id) AS relative_path,              -- Stable, DAG-derived location for this ChangeLog row. Root segment 'change-log' + the row's primary key.
  calc_change_log_iri(t.change_log_id) AS iri,                                  -- Opaque stable identifier (the dash-form of RelativePath).
  calc_change_log_name(t.change_log_id) AS name,                                -- Human-readable label: the version and date of this change.
  t.version,                                                                    -- The release version number this change shipped in (semantic versioning MAJOR.MINOR.PATCH). NTWF is currently at 1.1.0.
  t.change_date,                                                                -- The date of the change. One of the four facts NTWF governance requires every change-log entry to record.
  t.change_kind,                                                                -- Semantic-versioning class of the change: 'patch' (documentation/label/comment only, formal model unchanged), 'minor' (additive — new classes/properties/CBox concepts, backward compatible), or 'major' (breaking — class removed/renamed, domain/range change invalidating ABox triples, or a new disjointness axiom).
  t.motivating_question,                                                        -- The competency question that motivated the change. One of the four facts NTWF governance requires. Empty if the change was driven by an external-dependency update rather than a CQ.
  t.terms_affected,                                                             -- The ontology terms (classes/properties/concepts) the change added, removed, or modified. One of the four facts NTWF governance requires.
  t.rationale,                                                                  -- Why the change was made. NTWF governance requires every TBox/ABox modification to be logged with its rationale.
  t.approved_by,                                                                -- FK to the GovernanceRole (an Authority) that approved this change. Changes to CBox/ABox/TBox require authority review; a steward identifying a need is not enough.
  calc_change_log_is_breaking_change(t.change_log_id) AS is_breaking_change,    -- TRUE iff this is a major (breaking) change (ChangeKind = 'major') — requires explicit update, re-validation, and migration planning for any system on the prior version.
  calc_change_log_is_backward_compatible(t.change_log_id) AS is_backward_compatible-- TRUE iff systems on the prior version keep working against this release (ChangeKind is 'patch' or 'minor'). Patch and minor increments preserve backward compatibility; only major breaks it.
FROM change_log t;

-- ----------------------------------------------------------------------------
-- vw_vocabulary_reconciliations: Table: VocabularyReconciliations. External dependency change: when a borrowed term from a living standard (PROV-O, FOAF, Dublin Core, DCAT, Schema.org) is deprecated and re-homed into the NTWF namespace, the edit triggers a version bump and an owl:sameAs reconciliation relation declaring the old and new terms equivalent. The worked example: deprecating foaf:name, prepending the ntwf prefix to get ntwf:name, and asserting foaf:name owl:sameAs ntwf:name. Each row is one reconciliation, with the standard it came from and the version in which the reconciliation shipped.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_vocabulary_reconciliations CASCADE;
CREATE VIEW vw_vocabulary_reconciliations WITH (security_invoker = ON) AS
SELECT
  t.reconciliation_id,
  calc_vocabulary_reconciliations_relative_path(t.reconciliation_id) AS relative_path,-- Stable, DAG-derived location for this reconciliation row. Root segment 'reconciliations' + the row's primary key.
  calc_vocabulary_reconciliations_iri(t.reconciliation_id) AS iri,              -- Opaque stable identifier (the dash-form of RelativePath).
  calc_vocabulary_reconciliations_name(t.reconciliation_id) AS name,            -- Human-readable label: the sameAs relation between the deprecated term and its NTWF replacement.
  t.deprecated_term,                                                            -- The borrowed/deprecated term being reconciled (e.g. foaf:name).
  t.replacement_term,                                                           -- The NTWF-namespaced replacement term (e.g. ntwf:name).
  t.reconciliation_relation,                                                    -- The OWL relation asserting equivalence. NTWF uses owl:sameAs.
  t.source_standard,                                                            -- The external standard the deprecated term came from (PROV-O, FOAF, Dublin Core, DCAT, Schema.org).
  t.introduced_in_version,                                                      -- The NTWF release version in which this reconciliation shipped. Re-homing a term triggers a version bump.
  t.rationale                                                                   -- Why the term was re-homed (e.g. upstream deprecation; semantic-alignment shift).
FROM vocabulary_reconciliations t;

-- ----------------------------------------------------------------------------
-- vw_scenarios: View for Scenarios
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_scenarios CASCADE;
CREATE VIEW vw_scenarios WITH (security_invoker = ON) AS
SELECT
  t.scenario_id,                                                                -- Stable identifier for a curated demo scenario (a named set of raw-fact edits applied at once).
  calc_scenarios_relative_path(t.scenario_id) AS relative_path,                 -- DAG-derived location for this Scenario row: root segment 'scenarios' + the primary key.
  calc_scenarios_iri(t.scenario_id) AS iri,                                     -- Opaque stable identifier (dash-form of RelativePath).
  calc_scenarios_name(t.scenario_id) AS name,                                   -- Slug form of the human label.
  t.label,                                                                      -- Human-readable button label for this scenario in the picker.
  t.icon,                                                                       -- A single emoji shown beside the label in the picker.
  t.explanation,                                                                -- Plain-language description of what this scenario changes and what the reasoner will derive as a result. Shown in the floating scenario picker so the user knows what each preset does before applying it.
  t.sort_order,                                                                 -- Display order in the picker (ascending).
  t.is_reset,                                                                   -- True for the single 'restore baseline' scenario; the picker styles it as a secondary action.
  t.edits                                                                       -- JSON-encoded ordered list of raw-fact assignments this scenario applies. Each item is {class, id|match, set:{field:value,...}} where 'class' is a rulebook table (camelCase keys on the raw store), 'id' targets a row by its *Id primary key (or 'match':'first' for the singleton Workflow), and 'set' is the raw fields to assign. The backend replays this list against the active raw store, then re-reasons — the scenario NEVER sets a derived field. This is the single source of truth for what each demo scenario does; the app's picker and the apply endpoint both read it from here (same JSON-on-a-first-class-table pattern as __meta__'s JsonValue).
FROM scenarios t;

-- ----------------------------------------------------------------------------
-- vw_competency_questions: The article's literal acceptance suite — the eight leadership/competency questions the NTWF worked example must answer (Talisman, Intentional Arrangement, CQ1-CQ8). First-class data, not hardcoded UI strings: each row names the question, the substrate-computed field that ANSWERS it (TargetTable/TargetField, for cross-substrate traceability and the explainer-DAG drilldown), the answer kind, and the asserted ExpectedAnswer used to grade pass/fail. The live answer is always READ from the named computed column — never recomputed — so the CQ scoreboard is a projection of the model like every other lens. This is the CMCC-native home for the competency questions: the article treats them as acceptance criteria traceable to the rulebook, so they live in the rulebook.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_competency_questions CASCADE;
CREATE VIEW vw_competency_questions WITH (security_invoker = ON) AS
SELECT
  t.competency_question_id,                                                     -- Primary key. Stable slug for the competency question (cq-1 .. cq-8).
  calc_competency_questions_relative_path(t.competency_question_id) AS relative_path,-- Stable, DAG-derived location for this CompetencyQuestion row. Root segment 'competency-questions' + the row's primary key. No leading slash so the Iri swap is a clean 1:1 substitution.
  calc_competency_questions_iri(t.competency_question_id) AS iri,               -- Opaque stable identifier (the dash-form of RelativePath). The OWL transpiler mints each individual's IRI from this value (erb:<Iri>), so identity is path-derived and globally unique.
  calc_competency_questions_name(t.competency_question_id) AS name,             -- Slug form of the DisplayName, for stable cross-reference. Mirrors the Name idiom used by the controlled-vocabulary tables.
  t.number,                                                                     -- The canonical 1-8 ordering of the competency questions as listed in the article / README.
  t.display_name,                                                               -- Short human label for the question (e.g. 'Steps and order').
  t.question_text,                                                              -- The full competency question, verbatim from the article's acceptance suite.
  t.target_table,                                                               -- The entity whose computed field answers this question. Together with TargetField it pins the answer to a real column in the substrate, so the scoreboard reads the answer (never recomputes it) and the explainer-DAG drilldown lands on the exact derivation.
  t.target_field,                                                               -- The substrate-computed field on TargetTable that answers this question (calc / lookup / aggregation / closure). The CQ scoreboard wraps the live answer in a DagCell(TargetTable, TargetField) so a click opens its inference graph.
  t.answer_kind,                                                                -- 'scalar' when the answer is a single value graded by equality with ExpectedAnswer; 'list' when the answer is a collection graded as answerable (non-empty / matches the asserted shape).
  t.expected_answer,                                                            -- The asserted correct answer for the seed worked example. For scalar questions the live computed value must equal this to score a pass; for list questions this is the canonical summary the rendered collection is checked against. Authored here so pass/fail is (substrate-computed value) vs (rulebook-asserted expectation) — a real conformance check, not UI logic.
  t.explanation,                                                                -- One-sentence note on how this question resolves through the model — the FK / formula chain a presenter can narrate.
  t.sort_order,                                                                 -- Display order in the scoreboard. Mirrors Number for now; kept separate so the list can be re-sequenced without renumbering the canonical CQ ids.
  t.is_active,                                                                  -- Whether this competency question is shown in the scoreboard. All eight are active in the worked example.
  t.simulate_scenario                                                           -- FK to the Scenario the card's 'Simulate' button applies to demonstrate this competency question live. Points at the minimal raw-fact edit that moves THIS question's answer in isolation where one exists; for cq-2 it points at 'ai-release-manager', which also ripples to cq-3 (the gate approver is itself a step executor, so the two answers cannot be perturbed independently). The full set of questions each scenario moves — trigger vs ripple — is enumerated in the ScenarioCQEffects junction; this is just the one the button fires. Inverse-ish of ScenarioCQEffects but kept as a direct FK so the UI has a single answer.
FROM competency_questions t;

-- ----------------------------------------------------------------------------
-- vw_scenario_cq_effects: Table: ScenarioCQEffects. Names the many-to-many between Scenarios and CompetencyQuestions as two 1:M foreign keys (Scenario, CompetencyQuestion) plus the detail of the relationship (EffectKind, Note). Each row asserts 'applying this scenario moves this competency question's live answer'. 'trigger' rows are the intended demonstration; 'ripple' rows record answers that move as an unavoidable consequence of the same raw edit (e.g. ai-release-manager moves cq-2 AND cq-3 because the gate approver is itself a step executor). The answers themselves are never stored here — they are read live from each substrate after the scenario applies.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_scenario_cq_effects CASCADE;
CREATE VIEW vw_scenario_cq_effects WITH (security_invoker = ON) AS
SELECT
  t.scenario_cq_effect_id,                                                      -- Primary key. '<scenario>-<cq>' — names one (scenario moves this competency question) edge.
  calc_scenario_cq_effects_relative_path(t.scenario_cq_effect_id) AS relative_path,-- DAG-derived location: 'scenario-cq-effects/' + the row's primary key.
  calc_scenario_cq_effects_iri(t.scenario_cq_effect_id) AS iri,                 -- Opaque stable identifier (dash-form of RelativePath).
  calc_scenario_cq_effects_name(t.scenario_cq_effect_id) AS name,               -- Slug label, mirrors the primary key.
  t.scenario,                                                                   -- FK to the Scenario whose raw-fact edits cause this effect. The 'many effects belong to one scenario' side: a single scenario can move several competency questions.
  t.competency_question,                                                        -- FK to the CompetencyQuestion whose live answer this scenario moves. The 'many effects belong to one question' side: a question can be exercised by several scenarios.
  t.effect_kind,                                                                -- 'trigger' = this scenario was authored to move this question (the point of the demo). 'ripple' = the question also moves as an unavoidable side effect of the same raw edit. The ripple rows are the pedagogical payload: they show answers that are structurally coupled and cannot be perturbed independently.
  t.note,                                                                       -- One-line, human-readable account of how this scenario moves this question's answer (qualitative — the actual value is read live from the substrate, never stored here).
  t.sort_order                                                                  -- Display order.
FROM scenario_cq_effects t;

-- ----------------------------------------------------------------------------
-- vw_conformance_tests: View for ConformanceTests
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_conformance_tests CASCADE;
CREATE VIEW vw_conformance_tests WITH (security_invoker = ON) AS
SELECT
  t.conformance_test_id,                                                        -- Stable identifier for one conformance test — one assertion the harness runs against every execution substrate.
  calc_conformance_tests_relative_path(t.conformance_test_id) AS relative_path, -- DAG-derived location for this test row: root segment 'conformance-tests' + the primary key.
  calc_conformance_tests_iri(t.conformance_test_id) AS iri,                     -- Slug IRI for this row, derived from RelativePath.
  calc_conformance_tests_name(t.conformance_test_id) AS name,                   -- Machine name derived from the display name.
  t.display_name,                                                               -- Human-readable test title shown in the admin console and run logs.
  t.feature_ref,                                                                -- Comma-separated FEATURE-COVERAGE.md ids this test witnesses (e.g. 'II-3,CQ2'). The traceability link from the article's feature inventory to an executable assertion.
  t.section,                                                                    -- Grouping for display: 'Sweep', 'Part I'..'Part IV', 'Closure', 'Mutation'.
  t.test_kind,                                                                  -- How the harness executes this test. 'sweep' = every row+field of TargetRef table vs the answer key; 'field-match' = one row's field vs the answer key; 'closure-contains' = a from→to pair must appear in the engine's computed transitive closure (Expect names the closure and pair); 'engines-agree' = zero value-class disagreements between the two engines; 'mutation' = apply Expect.edits to an in-memory copy of the seed facts, re-reason, and check Expect.assert — the store is NEVER written.
  t.target_ref,                                                                 -- What the test reads: 'Entity' (whole table), 'Entity/pk' (one row) or 'Entity/pk#Field' (one value). Slash/hash form on purpose — these are spec references, not foreign keys.
  t.expect,                                                                     -- Kind-specific JSON spec. Empty for sweep/field-match/engines-agree — there the ORACLE is the answer key (testing/answer-keys), never a value hardcoded here (a literal would go stale; the key regenerates). closure-contains: {closure, from, to}. mutation: {edits:[{class,id,set:{camelRawField:value}}], assert:[{class,id,field,equals}]} — same edits shape as Scenarios.Edits.
  t.explanation,                                                                -- Why this test exists — what feature of the model it flexes, in one sentence.
  t.sort_order,                                                                 -- Display/run order within the suite.
  t.is_enabled                                                                  -- Disabled tests are listed but not executed (parked, not deleted — the list stays the complete spec).
FROM conformance_tests t;

-- ----------------------------------------------------------------------------
-- vw_step_precedence_closure: Transitive closure of ntwf:precedesStep (an owl:TransitiveProperty). The 4 asserted edges (1→2, 2→3, 3→4, 4→5) imply the full 10-pair ordering closure — including the never-asserted step-1 → step-5. Materialized by the transpiler as the view vw_step_precedence_closure(from_id, to_id, hop_distance, is_inferred): 4 asserted (hop 1) + 6 inferred rows. This is the article's headline inference made to fire, not seeded.
-- Cycle-safe transitive closure of step_precedence(from_step -> to_step) [junction edge table].
-- Columns: from_id, to_id, hop_distance (shortest derivation), is_inferred
--          (TRUE iff no direct hop-1 edge asserts the pair).
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_precedence_closure CASCADE;
CREATE VIEW vw_step_precedence_closure WITH (security_invoker = ON) AS
WITH RECURSIVE edges AS (
    SELECT from_step AS from_id, to_step AS to_id
    FROM step_precedence
    -- Treat NULL and empty-string FKs as 'no edge' (the transpiler stores absent
    -- relationship values as '' rather than NULL, so both must be excluded).
    WHERE from_step IS NOT NULL AND from_step <> '' AND to_step IS NOT NULL AND to_step <> ''
),
closure AS (
    -- Base: the directly-asserted edges (hop 1).
    SELECT
        e.from_id,
        e.to_id,
        1 AS hop_distance,
        ARRAY[e.from_id, e.to_id] AS path
    FROM edges e
    UNION ALL
    -- Step: extend each path by one asserted edge, skipping nodes already on the
    -- path so cyclic edge sets terminate (cycle-safe).
    SELECT
        cl.from_id,
        e.to_id,
        cl.hop_distance + 1,
        cl.path || e.to_id
    FROM closure cl
    JOIN edges e ON e.from_id = cl.to_id
    WHERE NOT (e.to_id = ANY(cl.path))
)
SELECT
    cl.from_id,
    cl.to_id,
    MIN(cl.hop_distance) AS hop_distance,
    NOT EXISTS (
        SELECT 1 FROM edges e2
        WHERE e2.from_id = cl.from_id AND e2.to_id = cl.to_id
    ) AS is_inferred
FROM closure cl
GROUP BY cl.from_id, cl.to_id;


-- ----------------------------------------------------------------------------
-- vw_roles_closure: Transitive closure of ntwf:delegatesTo over the self-referential DelegatesTo FK. The asserted escalation edges (Release Manager → VP Engineering, VP Engineering → CTO) imply the never-asserted reachability Release Manager → CTO. Materialized as vw_roles_closure(from_id, to_id, hop_distance, is_inferred). This is the SQL equivalent of the SPARQL delegatesTo+ property path.
-- Cycle-safe transitive closure of roles(role_id -> delegates_to) [self-referential FK].
-- Columns: from_id, to_id, hop_distance (shortest derivation), is_inferred
--          (TRUE iff no direct hop-1 edge asserts the pair).
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_roles_closure CASCADE;
CREATE VIEW vw_roles_closure WITH (security_invoker = ON) AS
WITH RECURSIVE edges AS (
    SELECT role_id AS from_id, delegates_to AS to_id
    FROM roles
    -- Treat NULL and empty-string FKs as 'no edge' (the transpiler stores absent
    -- relationship values as '' rather than NULL, so both must be excluded).
    WHERE role_id IS NOT NULL AND role_id <> '' AND delegates_to IS NOT NULL AND delegates_to <> ''
),
closure AS (
    -- Base: the directly-asserted edges (hop 1).
    SELECT
        e.from_id,
        e.to_id,
        1 AS hop_distance,
        ARRAY[e.from_id, e.to_id] AS path
    FROM edges e
    UNION ALL
    -- Step: extend each path by one asserted edge, skipping nodes already on the
    -- path so cyclic edge sets terminate (cycle-safe).
    SELECT
        cl.from_id,
        e.to_id,
        cl.hop_distance + 1,
        cl.path || e.to_id
    FROM closure cl
    JOIN edges e ON e.from_id = cl.to_id
    WHERE NOT (e.to_id = ANY(cl.path))
)
SELECT
    cl.from_id,
    cl.to_id,
    MIN(cl.hop_distance) AS hop_distance,
    NOT EXISTS (
        SELECT 1 FROM edges e2
        WHERE e2.from_id = cl.from_id AND e2.to_id = cl.to_id
    ) AS is_inferred
FROM closure cl
GROUP BY cl.from_id, cl.to_id;


